import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it } from "vitest";
import { Popover, PopoverContent, PopoverTrigger } from "./Popover";

function PopoverExample() {
  return (
    <Popover>
      <PopoverTrigger>Open popover</PopoverTrigger>
      <PopoverContent>Popover content</PopoverContent>
    </Popover>
  );
}

describe("Popover", () => {
  it("connects trigger and content with ARIA", async () => {
    const user = userEvent.setup();

    render(<PopoverExample />);

    const trigger = screen.getByRole("button", { name: "Open popover" });
    await user.click(trigger);

    const popover = await screen.findByRole("dialog");
    expect(popover).toHaveTextContent("Popover content");
    expect(trigger).toHaveAttribute("aria-haspopup", "dialog");
    expect(trigger).toHaveAttribute("aria-expanded", "true");
    expect(trigger).toHaveAttribute("aria-controls", popover.id);
  });

  it("closes on Escape", async () => {
    const user = userEvent.setup();

    render(<PopoverExample />);

    await user.click(screen.getByRole("button", { name: "Open popover" }));
    expect(await screen.findByRole("dialog")).toBeInTheDocument();

    await user.keyboard("{Escape}");
    expect(screen.queryByRole("dialog")).not.toBeInTheDocument();
  });
});

"use client";

import {
  ButtonHTMLAttributes,
  HTMLAttributes,
  ReactNode,
  createContext,
  forwardRef,
  useContext,
  useEffect,
  useId,
  useRef,
  useState,
} from "react";
import { createPortal } from "react-dom";
import { Slot, cn, composeRefs, swirskiAttrs } from "../../system";
import { usePortalRoot } from "../../system/usePortalRoot";

export type PopoverVariant = "default" | "compact";
export type PopoverSize = "sm" | "md" | "lg";
export type PopoverTone = "default";

type PopoverContextValue = {
  open: boolean;
  setOpen: (open: boolean) => void;
  rootRef: React.RefObject<HTMLDivElement | null>;
  contentRef: React.RefObject<HTMLDivElement | null>;
  contentId: string;
};

const PopoverContext = createContext<PopoverContextValue | null>(null);

export type PopoverProps = {
  children: ReactNode;
  open?: boolean;
  defaultOpen?: boolean;
  onOpenChange?: (open: boolean) => void;
  variant?: PopoverVariant;
  size?: PopoverSize;
  tone?: PopoverTone;
} & HTMLAttributes<HTMLDivElement>;

function usePopover() {
  const context = useContext(PopoverContext);

  if (!context) {
    throw new Error("Popover components must be used inside Popover.");
  }

  return context;
}

export const Popover = forwardRef<HTMLDivElement, PopoverProps>(function Popover({
  children,
  open,
  defaultOpen = false,
  onOpenChange,
  className,
  variant = "default",
  size = "md",
  tone = "default",
  ...props
}, ref) {
  const contentId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const [internalOpen, setInternalOpen] = useState(defaultOpen);
  const isControlled = open !== undefined;
  const currentOpen = open ?? internalOpen;

  function setOpen(nextOpen: boolean) {
    if (!isControlled) {
      setInternalOpen(nextOpen);
    }

    onOpenChange?.(nextOpen);
  }

  useEffect(() => {
    if (!currentOpen) {
      return;
    }

    const handlePointerDown = (event: PointerEvent) => {
      const target = event.target as Node;

      if (
        !rootRef.current?.contains(target) &&
        !contentRef.current?.contains(target)
      ) {
        setOpen(false);
      }
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setOpen(false);
      }
    };

    window.addEventListener("pointerdown", handlePointerDown);
    window.addEventListener("keydown", handleKeyDown);

    return () => {
      window.removeEventListener("pointerdown", handlePointerDown);
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [currentOpen]);

  return (
    <PopoverContext.Provider
      value={{ open: currentOpen, setOpen, rootRef, contentRef, contentId }}
    >
      <div
        ref={composeRefs(rootRef, ref)}
        className={cn("relative w-fit", className)}
        {...swirskiAttrs("popover", { size, tone, variant })}
        {...props}
      >
        {children}
      </div>
    </PopoverContext.Provider>
  );
});

Popover.displayName = "Popover";

export type PopoverTriggerProps = ButtonHTMLAttributes<HTMLButtonElement> & {
  asChild?: boolean;
  variant?: PopoverVariant;
  size?: PopoverSize;
  tone?: PopoverTone;
};

const triggerSizeStyles: Record<PopoverSize, string> = {
  sm: "px-3 py-1.5 text-xs",
  md: "px-4 py-2",
  lg: "px-5 py-3 text-base",
};

export const PopoverTrigger = forwardRef<HTMLButtonElement, PopoverTriggerProps>(
  function PopoverTrigger({
  asChild = false,
  className,
  variant = "default",
  size = "md",
  tone = "default",
  onClick,
  ...props
}, ref) {
  const { contentId, open, setOpen } = usePopover();
  const Component = asChild ? Slot : "button";

  return (
    <Component
      ref={ref}
      className={cn(
        "border-4 border-black bg-white font-black uppercase shadow-[4px_4px_0_#0B0B0C] transition hover:translate-x-1 hover:translate-y-1 hover:shadow-none",
        triggerSizeStyles[size],
        variant === "compact" && "shadow-none",
        className,
      )}
      onClick={(event) => {
        onClick?.(event);

        if (!event.defaultPrevented) {
          setOpen(!open);
        }
      }}
      type={asChild ? undefined : "button"}
      aria-controls={open ? contentId : undefined}
      aria-expanded={open}
      aria-haspopup="dialog"
      {...swirskiAttrs("popover-trigger", { size, tone, variant })}
      {...props}
    />
  );
});

PopoverTrigger.displayName = "PopoverTrigger";

export type PopoverContentProps = HTMLAttributes<HTMLDivElement> & {
  align?: "start" | "end";
  variant?: PopoverVariant;
  size?: PopoverSize;
  tone?: PopoverTone;
};

export const PopoverContent = forwardRef<HTMLDivElement, PopoverContentProps>(
  function PopoverContent({
  className,
  align = "start",
  variant = "default",
  size = "md",
  tone = "default",
  style,
  ...props
}, ref) {
  const { contentId, contentRef, open, rootRef } = usePopover();
  const portalRoot = usePortalRoot();
  const [position, setPosition] = useState<{
    left: number;
    top: number;
  } | null>(null);

  useEffect(() => {
    if (!open) {
      setPosition(null);
      return;
    }

    function updatePosition() {
      const rect = rootRef.current?.getBoundingClientRect();

      if (!rect) {
        return;
      }

      setPosition({
        left: align === "end" ? rect.right : rect.left,
        top: rect.bottom + 8,
      });
    }

    updatePosition();
    window.addEventListener("resize", updatePosition);
    window.addEventListener("scroll", updatePosition, true);

    return () => {
      window.removeEventListener("resize", updatePosition);
      window.removeEventListener("scroll", updatePosition, true);
    };
  }, [align, open, rootRef]);

  if (!open || !position || !portalRoot) {
    return null;
  }

  return createPortal(
    <div
      ref={composeRefs(contentRef, ref)}
      className={cn(
        "fixed z-[1000] w-72 border-4 border-black bg-white p-4 shadow-[8px_8px_0_#0B0B0C]",
        variant === "compact" && "p-3 shadow-[4px_4px_0_#0B0B0C]",
        className,
      )}
      id={contentId}
      role="dialog"
      {...swirskiAttrs("popover-content", { size, tone, variant })}
      style={{
        left: position.left,
        top: position.top,
        transform: align === "end" ? "translateX(-100%)" : undefined,
        ...style,
      }}
      {...props}
    />,
    portalRoot,
  );
});

PopoverContent.displayName = "PopoverContent";

