import { RefObject, useEffect } from "react";

export type UseClickOutsideOptions = {
  enabled?: boolean;
  events?: Array<"mousedown" | "pointerdown" | "touchstart">;
};

export function useClickOutside<T extends HTMLElement>(
  ref: RefObject<T | null>,
  handler: (event: Event) => void,
  options: UseClickOutsideOptions = {},
) {
  const { enabled = true, events = ["pointerdown"] } = options;

  useEffect(() => {
    if (!enabled) {
      return;
    }

    const listener = (event: Event) => {
      const element = ref.current;

      if (!element || element.contains(event.target as Node)) {
        return;
      }

      handler(event);
    };

    events.forEach((eventName) => {
      document.addEventListener(eventName, listener);
    });

    return () => {
      events.forEach((eventName) => {
        document.removeEventListener(eventName, listener);
      });
    };
  }, [enabled, events, handler, ref]);
}

"use client";

import { useCallback, useEffect, useState } from "react";

export type UseClipboardOptions = {
  timeout?: number;
};

function copyWithTextarea(value: string) {
  const textarea = document.createElement("textarea");
  textarea.value = value;
  textarea.setAttribute("readonly", "");
  textarea.style.position = "fixed";
  textarea.style.top = "-9999px";
  document.body.appendChild(textarea);
  textarea.select();
  document.execCommand("copy");
  document.body.removeChild(textarea);
}

export function useClipboard({ timeout = 1600 }: UseClipboardOptions = {}) {
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    if (!copied) {
      return;
    }

    const timeoutId = window.setTimeout(() => setCopied(false), timeout);

    return () => window.clearTimeout(timeoutId);
  }, [copied, timeout]);

  const copy = useCallback(async (value: string) => {
    try {
      if (navigator.clipboard) {
        await navigator.clipboard.writeText(value);
      } else {
        copyWithTextarea(value);
      }

      setCopied(true);
      setError(null);
    } catch (copyError) {
      const nextError =
        copyError instanceof Error
          ? copyError
          : new Error("Unable to copy to clipboard.");

      setError(nextError);
      setCopied(false);
      throw nextError;
    }
  }, []);

  const reset = useCallback(() => {
    setCopied(false);
    setError(null);
  }, []);

  return { copied, copy, error, reset };
}

"use client";

import { Dispatch, SetStateAction, useCallback, useState } from "react";

export type UseControllableStateProps<T> = {
  value?: T;
  defaultValue: T;
  onChange?: (value: T) => void;
};

export function useControllableState<T>({
  value,
  defaultValue,
  onChange,
}: UseControllableStateProps<T>): [T, Dispatch<SetStateAction<T>>] {
  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = value !== undefined;
  const currentValue = isControlled ? value : internalValue;

  const setValue = useCallback<Dispatch<SetStateAction<T>>>(
    (nextValue) => {
      const resolvedValue =
        typeof nextValue === "function"
          ? (nextValue as (currentValue: T) => T)(currentValue as T)
          : nextValue;

      if (!isControlled) {
        setInternalValue(resolvedValue);
      }

      onChange?.(resolvedValue);
    },
    [currentValue, isControlled, onChange],
  );

  return [currentValue as T, setValue];
}

"use client";

import { useCallback } from "react";
import { useControllableState } from "../use-controllable-state";

export type UseDisclosureHandlers = {
  open: () => void;
  close: () => void;
  toggle: () => void;
  set: (opened: boolean) => void;
};

export type UseDisclosureOptions = {
  value?: boolean;
  onChange?: (opened: boolean) => void;
};

export function useDisclosure(
  defaultOpened = false,
  options: UseDisclosureOptions = {},
): [boolean, UseDisclosureHandlers] {
  const [opened, setOpened] = useControllableState({
    value: options.value,
    defaultValue: defaultOpened,
    onChange: options.onChange,
  });

  const open = useCallback(() => setOpened(true), [setOpened]);
  const close = useCallback(() => setOpened(false), [setOpened]);
  const toggle = useCallback(
    () => setOpened((currentOpened) => !currentOpened),
    [setOpened],
  );

  return [opened, { open, close, toggle, set: setOpened }];
}

"use client";

import { useEffect } from "react";

export type UseEscapeKeyOptions = {
  enabled?: boolean;
  target?: Document | HTMLElement | Window | null;
};

export function useEscapeKey(
  handler: (event: KeyboardEvent) => void,
  options: UseEscapeKeyOptions = {},
) {
  const { enabled = true, target } = options;

  useEffect(() => {
    if (!enabled) {
      return;
    }

    const eventTarget = target ?? document;

    const listener = (event: Event) => {
      const keyboardEvent = event as KeyboardEvent;

      if (keyboardEvent.key === "Escape") {
        handler(keyboardEvent);
      }
    };

    eventTarget.addEventListener("keydown", listener);

    return () => eventTarget.removeEventListener("keydown", listener);
  }, [enabled, handler, target]);
}

